<span class="line"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">    whitened = (values - mean) * torch.rsqrt(var + </span><span style="--shiki-light:#098658;--shiki-dark:#B5CEA8;">1e-8</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">)</span></span>
